// // This module selects between two 8-bit inputs based on the 'seleccion' signal. When 'seleccion' is HIGH, the output 'salida_bus' reflects the value of 'direccion'.
module top_module(

input [7:0] direccion,
input [7:0] dato,
input seleccion,
output [7:0] salida_bus

    );assign salida_bus = seleccion ? dato : direccion;

endmodule
